@st.cache_resource(show_spinner=False)
def load_model():
    try:
        if not os.path.exists(MODEL_PATH):
            with st.spinner("⬇️ Downloading model... Please wait..."):
                url = f"https://drive.google.com/uc?id={DRIVE_FILE_ID}"
                gdown.download(url, MODEL_PATH, quiet=False)
        session = ort.InferenceSession(MODEL_PATH)
        return session
    except Exception as e:
        st.error(f"❌ Failed to load model: {e}")
        return None

def run_predict(model, image):
    arr        = preprocess_image(image)
    input_name = model.get_inputs()[0].name
    probs      = model.run(None, {input_name: arr})[0][0]
    order      = np.argsort(probs)[::-1]
    return [(CLASSES[i], float(probs[i])) for i in order]


def img_to_b64(path):
    # Photo is embedded directly as base64 for reliability
    return ""

def preprocess_image(image):
    img = image.convert('RGB').resize(IMG_SIZE, Image.LANCZOS)
    arr = np.array(img, dtype=np.float32)
    arr = arr[..., ::-1]      # RGB to BGR
    arr[..., 0] -= 103.939
    arr[..., 1] -= 116.779
    arr[..., 2] -= 123.68
    return np.expand_dims(arr, axis=0)


